import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../../utils/api';
import Spinner from '../../components/common/Spinner';
import toast from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';
import {
  FiBell, FiStar, FiUser, FiPackage,
  FiMapPin, FiPhone, FiCheckCircle,
} from 'react-icons/fi';

const getTimeAgo = (dateStr) => {
  const diff = Math.floor((Date.now() - new Date(dateStr)) / 60000);
  if (diff < 1) return 'Just now';
  if (diff < 60) return `${diff} min away`;
  return `${Math.floor(diff / 60)} hr ago`;
};

const DeliveryDashboard = () => {
  const { user } = useAuth();

  const [available, setAvailable] = useState([]);
  const [myDeliveries, setMyDeliveries] = useState([]);
  const [loading, setLoading] = useState(true);
  const [verifyCode, setVerifyCode] = useState({});
  const [active, setActive] = useState(null);

  const loadData = async () => {
    setLoading(true);
    try {
      const [availRes, myRes] = await Promise.all([
        api.get('/delivery/available'),
        api.get('/delivery/my'),
      ]);

      const avail = availRes.data.deliveries || [];
      const mine = myRes.data.deliveries || [];

      setAvailable(avail);
      setMyDeliveries(mine);

      const activeOne = mine.find(d =>
        ['assigned', 'picked_up', 'in_transit'].includes(d.deliveryStatus)
      );

      setActive(activeOne || null);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const acceptDelivery = async (id) => {
    try {
      const res = await api.put(`/delivery/${id}/accept`);

      // 🔥 SHOW OTP FOR TESTING
      console.log("OTP:", res.data.otp);

      toast.success('Delivery accepted!');
      loadData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed');
    }
  };

  const updateStatus = async (id, status) => {
    try {
      // 🔥 OTP REQUIRED ONLY FOR DELIVERY
      if (status === 'delivered' && !verifyCode[id]) {
        toast.error("Please enter OTP");
        return;
      }

      await api.put(`/delivery/${id}/status`, {
        status,
        verificationCode: verifyCode[id],
      });

      toast.success(`Marked as ${status.replace(/_/g, ' ')}`);
      loadData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Invalid OTP ❌');
    }
  };

  if (loading) return <Spinner />;

  return (
    <div className="min-h-screen bg-gray-50">

      <div className="max-w-2xl mx-auto px-4 py-5">

        {/* ACTIVE DELIVERY */}
        {active && (
          <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-5 mb-5">

            <p className="font-bold text-gray-800 mb-3">
              Active Delivery (ORD-{active.order?._id?.slice(-5)})
            </p>

            {/* OTP INPUT */}
            {active.deliveryStatus === 'in_transit' && (
              <input
                placeholder="Enter OTP from customer"
                className="w-full border border-gray-200 rounded-xl px-3 py-2 text-sm mb-3"
                value={verifyCode[active._id] || ''}
                onChange={e =>
                  setVerifyCode(prev => ({
                    ...prev,
                    [active._id]: e.target.value
                  }))
                }
              />
            )}

            {/* BUTTONS */}
            {active.deliveryStatus === 'assigned' && (
              <button
                onClick={() => updateStatus(active._id, 'picked_up')}
                className="w-full bg-green-500 text-white py-2 rounded"
              >
                Picked Up
              </button>
            )}

            {active.deliveryStatus === 'picked_up' && (
              <button
                onClick={() => updateStatus(active._id, 'in_transit')}
                className="w-full bg-green-500 text-white py-2 rounded"
              >
                In Transit
              </button>
            )}

            {active.deliveryStatus === 'in_transit' && (
              <button
                onClick={() => updateStatus(active._id, 'delivered')}
                className="w-full bg-green-500 text-white py-2 rounded"
              >
                Mark Delivered
              </button>
            )}
          </div>
        )}

        {/* AVAILABLE DELIVERIES */}
        {available.length > 0 && (
          <div>
            <h2 className="font-bold mb-3">
              Available Deliveries ({available.length})
            </h2>

            {available.map(delivery => (
              <div key={delivery._id} className="bg-white p-4 mb-3 rounded shadow">
                <p className="font-bold">
                  ORD-{delivery.order?._id?.slice(-5)}
                </p>

                <button
                  onClick={() => acceptDelivery(delivery._id)}
                  className="mt-2 bg-orange-500 text-white px-4 py-2 rounded"
                >
                  Accept Delivery
                </button>
              </div>
            ))}
          </div>
        )}

        {/* NO DATA */}
        {available.length === 0 && !active && (
          <div className="text-center text-gray-400 mt-10">
            No deliveries available
          </div>
        )}

      </div>
    </div>
  );
};

export default DeliveryDashboard;
